132: void ActiveTcpListener::pauseListening() {
133:   if (listener_ != nullptr) {
134:     listener_->disable();
135:   }
136: }
137: 
138: void ActiveTcpListener::resumeListening() {
139:   if (listener_ != nullptr) {
140:     listener_->enable();
141:   }
142: }
