149: void ActiveTcpListener::newActiveConnection(const Network::FilterChain& filter_chain,
150:                                             Network::ServerConnectionPtr server_conn_ptr,
151:                                             std::unique_ptr<StreamInfo::StreamInfo> stream_info) {
152:   auto& active_connections = getOrCreateActiveConnections(filter_chain);
153:   auto active_connection =
154:       std::make_unique<ActiveTcpConnection>(active_connections, std::move(server_conn_ptr),
155:                                             dispatcher().timeSource(), std::move(stream_info));
156:   // If the connection is already closed, we can just let this connection immediately die.
157:   if (active_connection->connection_->state() != Network::Connection::State::Closed) {
158:     ENVOY_CONN_LOG(
159:         debug, "new connection from {}", *active_connection->connection_,
160:         active_connection->connection_->connectionInfoProvider().remoteAddress()->asString());
161:     active_connection->connection_->addConnectionCallbacks(*active_connection);
162:     LinkedList::moveIntoList(std::move(active_connection), active_connections.connections_);
163:   }
164: }
165: 
166: void ActiveTcpListener::post(Network::ConnectionSocketPtr&& socket) {
167:   // It is not possible to capture a unique_ptr because the post() API copies the lambda, so we must
168:   // bundle the socket inside a shared_ptr that can be captured.
169:   // TODO(mattklein123): It may be possible to change the post() API such that the lambda is only
170:   // moved, but this is non-trivial and needs investigation.
171:   RebalancedSocketSharedPtr socket_to_rebalance = std::make_shared<RebalancedSocket>();
172:   socket_to_rebalance->socket = std::move(socket);
173: 
174:   dispatcher().post([socket_to_rebalance, address = listen_address_, tag = config_->listenerTag(),
175:                      &tcp_conn_handler = tcp_conn_handler_,
176:                      handoff = config_->handOffRestoredDestinationConnections()]() {
177:     auto balanced_handler = tcp_conn_handler.getBalancedHandlerByTag(tag, *address);
178:     if (balanced_handler.has_value()) {
179:       balanced_handler->get().onAcceptWorker(std::move(socket_to_rebalance->socket), handoff, true);
180:       return;
181:     }
182:   });
183: }
