93:       conn_length_(new Stats::HistogramCompletableTimespanImpl(
94:           active_connections_.listener_.stats_.downstream_cx_length_ms_, time_source)) {
95:   // We just universally set no delay on connections. Theoretically we might at some point want
96:   // to make this configurable.
97:   connection_->noDelay(true);
98:   auto& listener = active_connections_.listener_;
99:   listener.stats_.downstream_cx_total_.inc();
100:   listener.stats_.downstream_cx_active_.inc();
101:   listener.per_worker_stats_.downstream_cx_total_.inc();
102:   listener.per_worker_stats_.downstream_cx_active_.inc();
103: 
104:   // Active connections on the handler (not listener). The per listener connections have already
105:   // been incremented at this point either via the connection balancer or in the socket accept
106:   // path if there is no configured balancer.
107:   listener.parent_.incNumConnections();
