73: void ActiveTcpSocket::createListenerFilterBuffer() {
74:   listener_filter_buffer_ = std::make_unique<Network::ListenerFilterBufferImpl>(
75:       socket_->ioHandle(), listener_.dispatcher(),
76:       [this](bool error) {
77:         socket_->ioHandle().close();
78:         if (error) {
79:           listener_.stats_.downstream_listener_filter_error_.inc();
80:         } else {
81:           listener_.stats_.downstream_listener_filter_remote_close_.inc();
82:         }
83:         continueFilterChain(false);
84:       },
85:       [this](Network::ListenerFilterBufferImpl& filter_buffer) {
86:         Network::FilterStatus status = (*iter_)->onData(filter_buffer);
87:         if (status == Network::FilterStatus::StopIteration) {
88:           if (socket_->ioHandle().isOpen()) {
89:             // The listener filter should not wait for more data when it has already received
90:             // all the data it requested.
91:             ASSERT(filter_buffer.rawSlice().len_ < (*iter_)->maxReadBytes());
92:             // Check if the maxReadBytes is changed or not. If change,
93:             // reset the buffer capacity.
94:             if ((*iter_)->maxReadBytes() > filter_buffer.capacity()) {
95:               filter_buffer.resetCapacity((*iter_)->maxReadBytes());
96:               // Activate `Read` event manually in case the data already
97:               // available in the socket buffer.
98:               filter_buffer.activateFileEvent(Event::FileReadyType::Read);
99:             }
100:           } else {
101:             // The filter closed the socket.
102:             continueFilterChain(false);
103:           }
104:           return;
105:         }
106:         continueFilterChain(true);
107:       },
108:       (*iter_)->maxReadBytes() == 0, (*iter_)->maxReadBytes());
109: }
110: 
111: void ActiveTcpSocket::continueFilterChain(bool success) {
112:   if (success) {
113:     bool no_error = true;
114:     if (iter_ == accept_filters_.end()) {
115:       iter_ = accept_filters_.begin();
116:     } else {
117:       iter_ = std::next(iter_);
118:     }
119: 
120:     for (; iter_ != accept_filters_.end(); iter_++) {
121:       Network::FilterStatus status = (*iter_)->onAccept(*this);
122:       if (status == Network::FilterStatus::StopIteration) {
123:         // The filter is responsible for calling us again at a later time to continue the filter
124:         // chain from the next filter.
125:         if (!socket().ioHandle().isOpen()) {
126:           // Break the loop but should not create new connection.
127:           no_error = false;
128:           break;
129:         } else {
130:           // There are two cases for returning StopIteration. One is listener filter
131:           // needs to wait for data. The other is listener filter with 0 maxReadBytes()
132:           // doesn't inspect data, but needs to wait for some asynchronous callback and
133:           // listener filter buffer needs to listen for socket close event.
134:           if (listener_filter_buffer_ == nullptr) {
135:             createListenerFilterBuffer();
136:           }
137:           if ((*iter_)->maxReadBytes() > 0) {
138:             listener_filter_buffer_->disableOnDataCallback(false);
139:             // If the current filter expect more data than previous filters, then
140:             // increase the filter buffer's capacity.
141:             if (listener_filter_buffer_->capacity() < (*iter_)->maxReadBytes()) {
142:               listener_filter_buffer_->resetCapacity((*iter_)->maxReadBytes());
143:             }
144:             if (listener_filter_buffer_ != nullptr) {
145:               // There are two cases for activate event manually: One is
146:               // the data is already available when connect, activate the read event to peek
147:               // data from the socket . Another one is the data already
148:               // peeked into the buffer when previous filter processing the data, then activate the
149:               // read event to trigger the current filter callback to process the data.
150:               listener_filter_buffer_->activateFileEvent(Event::FileReadyType::Read);
151:             }
152:           } else {
153:             listener_filter_buffer_->disableOnDataCallback(true);
154:           }
155: 
156:           return;
157:         }
158:       }
159:     }
160:     // Successfully ran all the accept filters.
161:     if (no_error) {
162:       newConnection();
163:     } else {
164:       // Signal the caller that no extra filter chain iteration is needed.
165:       iter_ = accept_filters_.end();
166:     }
167:   }
168: 
169:   // Filter execution concluded, unlink and delete this ActiveTcpSocket if it was linked.
170:   if (inserted()) {
171:     unlink();
172:   }
173: }
