{"content":"387: RequestDecoder& ConnectionManagerImpl::newStream(ResponseEncoder& response_encoder,
388:                                                  bool is_internally_created) {
389:   TRACE_EVENT("core", "ConnectionManagerImpl::newStream");
390:   if (connection_idle_timer_) {
391:     connection_idle_timer_->disableTimer();
392:   }
393: 
394:   ENVOY_CONN_LOG(debug, "new stream", read_callbacks_->connection());
395: 
396:   Buffer::BufferMemoryAccountSharedPtr downstream_stream_account =
397:       response_encoder.getStream().account();
398: 
399:   if (downstream_stream_account == nullptr) {
400:     // Create account, wiring the stream to use it for tracking bytes.
401:     // If tracking is disabled, the wiring becomes a NOP.
402:     auto& buffer_factory = dispatcher_->getWatermarkFactory();
403:     downstream_stream_account = buffer_factory.createAccount(response_encoder.getStream());
404:     response_encoder.getStream().setAccount(downstream_stream_account);
405:   }
406: 
407:   auto new_stream = std::make_unique<ActiveStream>(
408:       *this, response_encoder.getStream().bufferLimit(), std::move(downstream_stream_account));
409: 
410:   accumulated_requests_++;
411:   if (config_->maxRequestsPerConnection() > 0 &&
412:       accumulated_requests_ >= config_->maxRequestsPerConnection()) {
413:     if (codec_->protocol() < Protocol::Http2) {
414:       new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
415:       // Prevent erroneous debug log of closing due to incoming connection close header.
416:       drain_state_ = DrainState::Closing;
417:     } else if (drain_state_ == DrainState::NotDraining) {
418:       startDrainSequence();
419:     }
420:     ENVOY_CONN_LOG(debug, "max requests per connection reached", read_callbacks_->connection());
421:     stats_.named_.downstream_cx_max_requests_reached_.inc();
422:   }
423: 
424:   if (soft_drain_http1_) {
425:     new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
426:     // Prevent erroneous debug log of closing due to incoming connection close header.
427:     drain_state_ = DrainState::Closing;
428:   }
429: 
430:   new_stream->state_.is_internally_created_ = is_internally_created;
431:   new_stream->response_encoder_ = &response_encoder;
432:   new_stream->response_encoder_->getStream().addCallbacks(*new_stream);
433:   new_stream->response_encoder_->getStream().registerCodecEventCallbacks(new_stream.get());
434:   new_stream->response_encoder_->getStream().setFlushTimeout(new_stream->idle_timeout_ms_);
435:   new_stream->streamInfo().setDownstreamBytesMeter(response_encoder.getStream().bytesMeter());
436:   // If the network connection is backed up, the stream should be made aware of it on creation.
437:   // Both HTTP/1.x and HTTP/2 codecs handle this in StreamCallbackHelper::addCallbacksHelper.
438:   ASSERT(read_callbacks_->connection().aboveHighWatermark() == false ||
439:          new_stream->filter_manager_.aboveHighWatermark());
440:   LinkedList::moveIntoList(std::move(new_stream), streams_);
441:   return **streams_.begin();
442: }
