50: void ActiveStreamFilterBase::commonContinue() {
51:   if (!canContinue()) {
52:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
53:                      static_cast<const void*>(this));
54:     return;
55:   }
56: 
57:   // Set ScopeTrackerScopeState if there's no existing crash context.
58:   ScopeTrackedObjectStack encapsulated_object;
59:   absl::optional<ScopeTrackerScopeState> state;
60:   if (parent_.dispatcher_.trackedObjectStackIsEmpty()) {
61:     restoreContextOnContinue(encapsulated_object);
62:     state.emplace(&encapsulated_object, parent_.dispatcher_);
63:   }
64: 
65:   ENVOY_STREAM_LOG(trace, "continuing filter chain: filter={}", *this,
66:                    static_cast<const void*>(this));
67:   ASSERT(!canIterate(),
68:          "Attempting to continue iteration while the IterationState is already Continue");
69:   // If iteration has stopped for all frame types, set iterate_from_current_filter_ to true so the
70:   // filter iteration starts with the current filter instead of the next one.
71:   if (stoppedAll()) {
72:     iterate_from_current_filter_ = true;
73:   }
74:   allowIteration();
75: 
76:   // Only resume with do1xxHeaders() if we've actually seen 1xx headers.
77:   if (has1xxHeaders()) {
78:     continued_1xx_headers_ = true;
79:     do1xxHeaders();
80:     // If the response headers have not yet come in, don't continue on with
81:     // headers and body. doHeaders expects request headers to exist.
82:     if (!parent_.filter_manager_callbacks_.responseHeaders()) {
83:       return;
84:     }
85:   }
86: 
87:   // Make sure that we handle the zero byte data frame case. We make no effort to optimize this
88:   // case in terms of merging it into a header only request/response. This could be done in the
89:   // future.
90:   if (!headers_continued_) {
91:     headers_continued_ = true;
92:     doHeaders(observedEndStream() && !bufferedData() && !hasTrailers());
93:   }
94: 
95:   doMetadata();
96: 
97:   // It is possible for trailers to be added during doData(). doData() itself handles continuation
98:   // of trailers for the non-continuation case. Thus, we must keep track of whether we had
99:   // trailers prior to calling doData(). If we do, then we continue them here, otherwise we rely
100:   // on doData() to do so.
