537: void FilterManager::decodeHeaders(ActiveStreamDecoderFilter* filter, RequestHeaderMap& headers,
538:                                   bool end_stream) {
539:   // Headers filter iteration should always start with the next filter if available.
540:   StreamDecoderFilters::Iterator entry =
541:       commonDecodePrefix(filter, FilterIterationStartState::AlwaysStartFromNext);
542:   StreamDecoderFilters::Iterator continue_data_entry = decoder_filters_.end();
543:   bool terminal_filter_decoded_end_stream = false;
544:   ASSERT(!state_.decoder_filter_chain_complete_ || entry == decoder_filters_.end() ||
545:          (*entry)->end_stream_);
546: 
547:   for (; entry != decoder_filters_.end(); entry++) {
548:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
549:     ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeHeaders));
550:     state_.filter_call_state_ |= FilterCallState::DecodeHeaders;
551:     (*entry)->end_stream_ = (end_stream && continue_data_entry == decoder_filters_.end());
552:     if ((*entry)->end_stream_) {
553:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
554:     }
555:     FilterHeadersStatus status = (*entry)->decodeHeaders(headers, (*entry)->end_stream_);
556:     state_.filter_call_state_ &= ~FilterCallState::DecodeHeaders;
557:     if ((*entry)->end_stream_) {
558:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
559:     }
560:     if (state_.decoder_filter_chain_aborted_) {
561:       executeLocalReplyIfPrepared();
562:       ENVOY_STREAM_LOG(trace,
563:                        "decodeHeaders filter iteration aborted due to local reply: filter={}",
564:                        *this, (*entry)->filter_context_.config_name);
565:       status = FilterHeadersStatus::StopIteration;
566:     }
567: 
568:     ASSERT(!(status == FilterHeadersStatus::ContinueAndDontEndStream && !(*entry)->end_stream_),
569:            "Filters should not return FilterHeadersStatus::ContinueAndDontEndStream from "
570:            "decodeHeaders when end_stream is already false");
571: 
572:     ENVOY_STREAM_LOG(trace, "decode headers called: filter={} status={}", *this,
573:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
574: 
575:     (*entry)->processed_headers_ = true;
576: 
577:     const auto continue_iteration = (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
578:     ENVOY_BUG(!continue_iteration || !stopDecoderFilterChain(),
579:               fmt::format(
580:                   "filter={} did not return StopAll or StopIteration after sending a local reply.",
581:                   (*entry)->filter_context_.config_name));
582: 
583:     // If this filter ended the stream, decodeComplete() should be called for it.
584:     if ((*entry)->end_stream_) {
585:       (*entry)->handle_->decodeComplete();
586:     }
587: 
588:     // Skip processing metadata after sending local reply
589:     if (stopDecoderFilterChain() && std::next(entry) != decoder_filters_.end()) {
590:       maybeContinueDecoding(continue_data_entry);
591:       return;
592:     }
593: 
594:     const bool new_metadata_added = processNewlyAddedMetadata();
595:     // If end_stream is set in headers, and a filter adds new metadata, we need to delay end_stream
596:     // in headers by inserting an empty data frame with end_stream set. The empty data frame is sent
597:     // after the new metadata.
598:     if ((*entry)->end_stream_ && new_metadata_added && !buffered_request_data_) {
599:       Buffer::OwnedImpl empty_data("");
600:       ENVOY_STREAM_LOG(
601:           trace, "inserting an empty data frame for end_stream due metadata being added.", *this);
602:       // Metadata frame doesn't carry end of stream bit. We need an empty data frame to end the
603:       // stream.
604:       addDecodedData(*(*entry), empty_data, true);
605:     }
606: 
607:     if (!continue_iteration && std::next(entry) != decoder_filters_.end()) {
608:       // Stop iteration IFF this is not the last filter. If it is the last filter, continue with
609:       // processing since we need to handle the case where a terminal filter wants to buffer, but
610:       // a previous filter has added body.
611:       maybeContinueDecoding(continue_data_entry);
612:       return;
613:     }
614: 
615:     // Here we handle the case where we have a header only request, but a filter adds a body
616:     // to it. We need to not raise end_stream = true to further filters during inline iteration.
617:     if (end_stream && buffered_request_data_ && continue_data_entry == decoder_filters_.end()) {
618:       continue_data_entry = entry;
619:     }
620:     // The decoder filter chain is finished here if the following is true:
621:     // 1. the last filter has observed the end_stream AND
622:     // 2. no filter, including the last filter, has injected body during header iteration.
623:     // If body was injected the end_stream will be processed in the `decodeData()` method below.
624:     const bool no_body_was_injected = continue_data_entry == decoder_filters_.end();
625:     terminal_filter_decoded_end_stream =
626:         (std::next(entry) == decoder_filters_.end() && (*entry)->end_stream_) &&
627:         no_body_was_injected;
628:   }
629: 
630:   maybeContinueDecoding(continue_data_entry);
